Use an AWS Glue job triggered by S3 PUT events or a daily schedule to read invoices.csv, apply a fixed target schema, fill missing columns with defaults, cast data types appropriately, and write Parquet to s3://company-data/warehouse/invoices/ using date-based partitioning. Implement idempotency by storing a checkpoint in DynamoDB after each successful date load, checking for existing entries before processing.

```python
import boto3
from datetime import datetime
from pyspark.sql.functions import lit

dynamodb = boto3.resource('dynamodb')
table = dynamodb.Table('pipeline_checkpoints')

def is_processed(vendor_id: str, date_str: str) -> bool:
    response = table.get_item(Key={'vendor_id': vendor_id, 'date': date_str})
    return 'Item' in response

def write_checkpoint(vendor_id: str, date_str: str) -> None:
    table.put_item(Item={
        'vendor_id': vendor_id,
        'date': date_str,
        'processed_at': datetime.utcnow().isoformat()
    })

def normalize_schema(df):
    target_schema = ['invoice_id', 'vendor_id', 'amount', 'currency', 'invoice_date']
    for col in target_schema:
        if col not in df.columns:
            df = df.withColumn(col, lit(None))
    return df.select(target_schema)

def process_invoices(event, context):
    for record in event['Records']:
        bucket = record['s3']['bucket']['name']
        key = record['s3']['object']['key']
        date_str = key.split('/')[4]
        vendor_id = record['s3']['object']['metadata'].get('vendor_id', 'unknown')

        if is_processed(vendor_id, date_str):
            print(f'Skipping already processed: {vendor_id}/{date_str}')
            continue

        df = spark.read.csv(f's3://{bucket}/{key}', header=True, inferSchema=True)
        normalized_df = normalize_schema(df)
        normalized_df.write.mode('overwrite').partitionBy('invoice_date').parquet(
            f's3://company-data/warehouse/invoices/{date_str}/'
        )
        write_checkpoint(vendor_id, date_str)
```

