function maskPII(value, type) {
  if (type === 'ssn') return value ? value.replace(/\d{3}-\d{2}-\d{4}/g, 'XXX-XX-XXXX') : value;
  if (type === 'email') {
    const [name, domain] = (value||'').split('@');
    return (name ? name[0] + '***' : '') + '@' + (domain||'');
  }
  return value;
}
