// Pseudo: mask email/phone in streaming records before land
function maskPII(record) {
  if (!record) return record;
  const r = {...record};
  if (r.user) {
    if (r.user.email) r.user.email = '***@***.com';
    if (r.user.phone) r.user.phone = '******';
  }
  return r;
}
```

